import sys

def prime_factors(k):
    factors = {}
    for p in [2, 3, 5]:
        count = 0
        while k % p == 0:
            count += 1
            k //= p
        if count > 0:
            factors[p] = count
    return factors

def solve():
    data = sys.stdin.read().split()
    t = int(data[0])
    index = 1
    results = []

    for _ in range(t):
        n = int(data[index])
        k = int(data[index + 1])
        index += 2
        a = list(map(int, data[index:index + n]))
        index += n

        k_factors = prime_factors(k)

        min_increments_per_prime = {}
        for p, needed in k_factors.items():
            min_increments_per_prime[p] = float('inf')
            for num in a:
                count = 0
                temp = num
                while temp % p == 0:
                    temp //= p
                    count += 1
                if count >= needed:
                    min_increments_per_prime[p] = 0
                else:
                    increments = needed - count
                    if increments < min_increments_per_prime[p]:
                        min_increments_per_prime[p] = increments

        total_operations = max(min_increments_per_prime.values())
        results.append(str(total_operations))
    print("\n".join(results))

