class Solution:
    def matrixSum(self, nums: List[List[int]]) -> int:
        # Sort each row in descending order
        for row in nums:
            row.sort(reverse=True)

        total_score = 0
        # Find the maximum length among all rows
        max_length = max(len(row) for row in nums)

        # Iterate through each "column" index
        for i in range(max_length):
            current_max = 0
            for row in nums:
                # If the current row has an element at index i
                if i < len(row):
                    # Update current_max if this element is larger
                    if row[i] > current_max:
                        current_max = row[i]
            total_score += current_max
        return total_score

