class Solution:
    def maximumOr(self, nums: List[int], k: int) -> int:
        n = len(nums)
        # Compute the initial OR of all elements
        base_or = 0
        for num in nums:
            base_or |= num

        max_or = base_or

        # For each element, try doubling it from 0 to k times
        for i in range(n):
            original_value = nums[i]
            for t in range(k + 1):
                # Double the element t times
                doubled_value = original_value << t
                # Compute OR with this element replaced
                current_or = 0
                for j in range(n):
                    if j == i:
                        current_or |= doubled_value
                    else:
                        current_or |= nums[j]
                # Update maximum OR
                if current_or > max_or:
                    max_or = current_or

        return max_or

