class Solution:
    def maxStrength(self, nums: List[int]) -> int:
        max_product = float('-inf')
        n = len(nums)
        # Generate all non-empty subsets using bitmask
        for mask in range(1, 1 << n):
            product = 1
            for i in range(n):
                if (mask & (1 << i)) != 0:
                    product *= nums[i]
            max_product = max(max_product, product)
        return max_product

