class Solution:
    def minExtraChar(self, s: str, dictionary: List[str]) -> int:
        word_set = set(dictionary)  # For O(1) lookups
        n = len(s)
        # Initialize DP array: dp[i] = min leftover chars for s[:i]
        dp = [0] + [float('inf')] * n

        for i in range(1, n + 1):
            # Assume the current character is leftover if no match found
            dp[i] = dp[i - 1] + 1
            # Check all possible substrings ending at position i-1
            for j in range(i):
                if s[j:i] in word_set:
                    # If s[j:i] is a dictionary word, update dp[i]
                    dp[i] = min(dp[i], dp[j])
        return dp[n]

