class Solution:
    def buyChoco(self, prices: List[int], money: int) -> int:
        min_sum = float('inf')  # Initialize with a large value to track the minimal valid sum
        n = len(prices)
        for i in range(n):
            for j in range(i + 1, n):
                current_sum = prices[i] + prices[j]
                if current_sum <= money and current_sum < min_sum:
                    min_sum = current_sum
        # If no valid pair was found, min_sum remains float('inf')
        if min_sum == float('inf'):
            return money
        else:
            return money - min_sum

class Solution:
    def count(self, num1: str, num2: str, min_sum: int, max_sum: int) -> int:
        MOD = 10**9 + 7

        def str_to_digits(s):
            return list(map(int, s))

        def count_numbers_upto(num_digits):
            # Digit DP to count numbers <= num_digits with digit sum constraints
            from functools import lru_cache

            length = len(num_digits)

            @lru_cache(None)
            def dfs(pos, sum_so_far, tight):
                # If we've processed all digits
                if pos == length:
                    # Check if sum is within bounds
                    return 1 if min_sum <= sum_so_far <= max_sum else 0

                limit = num_digits[pos] if tight else 9
                total = 0
                for digit in range(limit + 1):
                    new_tight = tight and (digit == limit)
                    new_sum = sum_so_far + digit
                    # Prune if sum exceeds max_sum early
                    if new_sum > max_sum:
                        continue
                    total += dfs(pos + 1, new_sum, new_tight)
                return total % MOD

            return dfs(0, 0, True)

        def decrement_str_num(s):
            # Decrement the number represented by string s by 1
            num_list = list(map(int, s))
            i = len(num_list) - 1
            while i >= 0:
                if num_list[i] > 0:
                    num_list[i] -= 1
                    break
                else:
                    num_list[i] = 9
                    i -= 1
            # Remove leading zeros if any
            while len(num_list) > 1 and num_list[0] == 0:
                num_list.pop(0)
            return ''.join(map(str, num_list))

        # Count numbers up to num2
        num2_digits = str_to_digits(num2)
        total_up_to_num2 = count_numbers_upto(num2_digits)

        # Count numbers up to num1 - 1
        if num1 == "1":
            total_up_to_num1_minus_1 = 0
        else:
            num1_minus_one = decrement_str_num(num1)
            num1_minus_one_digits = str_to_digits(num1_minus_one)
            total_up_to_num1_minus_1 = count_numbers_upto(num1_minus_one_digits)

        result = (total_up_to_num2 - total_up_to_num1_minus_1) % MOD
        return result

