class Solution:
    def colorTheArray(self, n: int, queries: List[List[int]]) -> List[int]:
        nums = [0] * n
        answer = []
        adjacentCount = 0

        for index, color in queries:
            old_color = nums[index]
            if old_color == color:
                # No change, just append current count
                answer.append(adjacentCount)
                continue

            # Check left neighbor
            if index > 0:
                if nums[index - 1] == old_color and old_color != 0:
                    adjacentCount -= 1
                if nums[index - 1] == color and color != 0:
                    adjacentCount += 1

            # Check right neighbor
            if index < n - 1:
                if nums[index + 1] == old_color and old_color != 0:
                    adjacentCount -= 1
                if nums[index + 1] == color and color != 0:
                    adjacentCount += 1

            # Update the current position with new color
            nums[index] = color

            # Append the current count after the update
            answer.append(adjacentCount)

        return answer

class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        max_length = 0
        left = 0
        pairs_count = 0  # count of consecutive pairs in current window

        for right in range(len(s)):
            # Check if current character forms a pair with previous
            if right > 0 and s[right] == s[right - 1]:
                pairs_count += 1

            # Shrink window from the left if more than one pair
            while pairs_count > 1:
                if s[left] == s[left + 1]:
                    pairs_count -= 1
                left += 1

            # Update maximum length for valid window
            max_length = max(max_length, right - left + 1)

        return max_length

