class Solution:
    def minLength(self, s: str) -> int:
        stack = []
        for char in s:
            stack.append(char)
            # Check if the last two characters form "AB" or "CD"
            if len(stack) >= 2:
                if (stack[-2] == 'A' and stack[-1] == 'B') or (stack[-2] == 'C' and stack[-1] == 'D'):
                    # Remove the last two characters
                    stack.pop()
                    stack.pop()
        return len(stack)

class Solution:
    def punishmentNumber(self, n: int) -> int:
        def can_partition(s: str, target: int, start: int, memo) -> bool:
            # If we've reached the end of the string, check if we've achieved the target sum
            if start == len(s):
                return target == 0
            if (start, target) in memo:
                return memo[(start, target)]
            # Try all possible substrings starting from 'start'
            for end in range(start + 1, len(s) + 1):
                num = int(s[start:end])
                # If the current number exceeds the remaining target, no need to proceed further
                if num > target:
                    break
                # Recurse with the remaining string and updated target
                if can_partition(s, target - num, end, memo):
                    memo[(start, target)] = True
                    return True
            memo[(start, target)] = False
            return False

        total = 0
        for i in range(1, n + 1):
            square_str = str(i * i)
            memo = {}
            # Check if square_str can be partitioned into substrings summing to i
            if can_partition(square_str, i, 0, memo):
                total += i * i
        return total

