class Solution:
    def paintWalls(self, cost: List[int], time: List[int]) -> int:
        n = len(cost)
        min_cost = float('inf')
        total_subsets = 1 << n  # Total number of subsets

        for mask in range(total_subsets):
            paid_time = 0
            paid_cost = 0
            remaining_walls = 0

            # Calculate total paid time and cost for the current subset
            for i in range(n):
                if (mask & (1 << i)) != 0:
                    paid_time += time[i]
                    paid_cost += cost[i]
                else:
                    remaining_walls += 1

            # Check if free painter can paint all remaining walls within paid_time
            # Each remaining wall takes 1 unit of time
            if remaining_walls <= paid_time:
                min_cost = min(min_cost, paid_cost)

        return min_cost

