class Solution:
    def minCost(self, nums: List[int], x: int) -> int:
        n = len(nums)
        min_total_cost = float('inf')
        for k in range(n):
            current_cost = 0
            for i in range(n):
                current_cost += nums[(i - k) % n] + k * x
            min_total_cost = min(min_total_cost, current_cost)
        return min_total_cost

class Solution:
    def minimumSum(self, n: int, k: int) -> int:
        selected = []
        selected_set = set()
        current = 1

        while len(selected) < n:
            # Check if adding current creates a forbidden pair
            if (k - current) not in selected_set:
                selected.append(current)
                selected_set.add(current)
            current += 1

        return sum(selected)

