        return num + 2 * t

class Solution:
    def makeSmallestPalindrome(self, s: str) -> str:
        s_list = list(s)
        i, j = 0, len(s) - 1
        while i < j:
            if s_list[i] != s_list[j]:
                # Replace the larger character with the smaller one
                if s_list[i] < s_list[j]:
                    s_list[j] = s_list[i]
                else:
                    s_list[i] = s_list[j]
            i += 1
            j -= 1
        return "".join(s_list)

class Solution:
    def minimumCost(self, s: str) -> int:
        n = len(s)

        def compute_cost(target):
            total_cost = 0
            flipped = False
            for i in range(n):
                current_char = s[i]
                if flipped:
                    current_char = '1' if current_char == '0' else '0'
                if current_char != target:
                    prefix_cost = i + 1
                    suffix_cost = n - i
                    if prefix_cost <= suffix_cost:
                        total_cost += prefix_cost
                        flipped = not flipped
                    else:
                        total_cost += suffix_cost
                        flipped = not flipped
            return total_cost

        return min(compute_cost('0'), compute_cost('1'))

