class Solution:
    def isFascinating(self, n: int) -> bool:
        double_n = 2 * n
        triple_n = 3 * n
        concatenated_str = str(n) + str(double_n) + str(triple_n)

        # Check if length is exactly 9
        if len(concatenated_str) != 9:
            return False

        # Check if '0' is present
        if '0' in concatenated_str:
            return False

        # Check if all digits from 1 to 9 are present exactly once
        digits_set = set(concatenated_str)
        return digits_set == set('123456789')

class Solution:
    def minimizedStringLength(self, s: str) -> int:
        from functools import lru_cache

        @lru_cache(None)
        def dfs(current_str):
            min_length = len(current_str)
            n = len(current_str)
            for i in range(n):
                c = current_str[i]
                # Find closest same character to the left
                left_idx = current_str.rfind(c, 0, i)
                # Find closest same character to the right
                right_idx = current_str.find(c, i + 1)
                if left_idx != -1 and right_idx != -1:
                    # Remove both occurrences
                    new_str = current_str[:left_idx] + current_str[left_idx+1:right_idx] + current_str[right_idx+1:]
                    min_length = min(min_length, dfs(new_str))
                elif left_idx != -1:
                    # Only left occurrence exists
                    new_str = current_str[:left_idx] + current_str[left_idx+1:]
                    min_length = min(min_length, dfs(new_str))
                elif right_idx != -1:
                    # Only right occurrence exists
                    new_str = current_str[:right_idx] + current_str[right_idx+1:]
                    min_length = min(min_length, dfs(new_str))
            return min_length

        return dfs(s)

