import math

class Solution:
    def canTraverseAllPairs(self, nums: List[int]) -> bool:
        n = len(nums)
        parent = list(range(n))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(x, y):
            rootX = find(x)
            rootY = find(y)
            if rootX != rootY:
                parent[rootY] = rootX

        # Map each prime factor to the list of indices sharing it
        factor_map = {}

        for i, num in enumerate(nums):
            # Factorize the number to its prime factors
            factors = set()
            temp = num
            # Check divisibility by 2
            while temp % 2 == 0:
                factors.add(2)
                temp //= 2
            # Check odd factors
            for f in range(3, int(math.sqrt(temp)) + 1, 2):
                while temp % f == 0:
                    factors.add(f)
                    temp //= f
            if temp > 1:
                factors.add(temp)

            # For each factor, union current index with all other indices sharing the same factor
            for factor in factors:
                if factor not in factor_map:
                    factor_map[factor] = i
                else:
                    union(i, factor_map[factor])

        # Check if all indices are connected
        root = find(0)
        for i in range(1, n):
            if find(i) != root:
                return False
        return True

class Solution:
    def smallestString(self, s: str) -> str:
        s_list = list(s)
        n = len(s_list)
        started = False

        for i in range(n):
            if s_list[i] > 'a':
                # Replace this character with its previous character
                s_list[i] = chr(ord(s_list[i]) - 1)
                started = True
            elif started:
                # Once we've started replacing, continue until we hit an 'a'
                # but if we encounter 'a', no need to continue as replacing 'a' with 'z' might not help
                # However, per the problem, we only replace once, so we stop after the first substring
                break

        return "".join(s_list)

