class Solution:
    def relocateMarbles(self, nums: List[int], moveFrom: List[int], moveTo: List[int]) -> List[int]:
        # Initialize a set with the initial positions of marbles
        occupied_positions = set(nums)

        # Process each move
        for f, t in zip(moveFrom, moveTo):
            # Move all marbles from 'f' to 't'
            if f in occupied_positions:
                occupied_positions.remove(f)
                occupied_positions.add(t)

        # Return the sorted list of occupied positions
        return sorted(occupied_positions)

class Solution:
    def makeTheIntegerZero(self, num1: int, num2: int) -> int:
        from collections import deque

        if num1 == 0:
            return 0

        visited = set()
        queue = deque()
        queue.append((num1, 0))
        visited.add(num1)

        while queue:
            current_num, steps = queue.popleft()
            if current_num == 0:
                return steps
            for i in range(61):
                val = (1 << i) + num2
                next_num = current_num - val
                if next_num < 0:
                    continue
                if next_num not in visited:
                    visited.add(next_num)
                    queue.append((next_num, steps + 1))
        return -1

