class Solution:
    def specialPerm(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)

        # Initialize DP array: dp[mask][i]
        # mask: bitmask of selected elements
        # i: index of last element in the permutation
        dp = [[0] * n for _ in range(1 << n)]

        # Base case: each element can start a permutation
        for i in range(n):
            dp[1 << i][i] = 1

        # Fill the DP table
        for mask in range(1 << n):
            for i in range(n):
                if dp[mask][i] == 0:
                    continue
                for j in range(n):
                    if mask & (1 << j) == 0:
                        # Check divisibility condition
                        if nums[i] % nums[j] == 0 or nums[j] % nums[i] == 0:
                            next_mask = mask | (1 << j)
                            dp[next_mask][j] = (dp[next_mask][j] + dp[mask][i]) % MOD

        # Sum all permutations that include all elements
        full_mask = (1 << n) - 1
        result = 0
        for i in range(n):
            result = (result + dp[full_mask][i]) % MOD

        return result

