class Solution:
    def sumImbalanceNumbers(self, nums: List[int]) -> int:
        total_imbalance = 0
        n = len(nums)
        for i in range(n):
            for j in range(i, n):
                subarray = nums[i:j+1]
                sarr = sorted(subarray)
                imbalance_count = 0
                for k in range(len(sarr) - 1):
                    if sarr[k+1] - sarr[k] > 1:
                        imbalance_count += 1
                total_imbalance += imbalance_count
        return total_imbalance

import heapq

class Solution:
    def longestString(self, x: int, y: int, z: int) -> int:
        heap = []
        if x > 0:
            heapq.heappush(heap, (-x, 'A'))
        if y > 0:
            heapq.heappush(heap, (-y, 'B'))
        if z > 0:
            heapq.heappush(heap, (-z, 'AB'))

        total_length = 0
        last_char = ''
        last_char_count = 0
        # We will keep track of the last character appended to prevent "AAA" or "BBB"
        # For "AB", since it contains both characters, it doesn't contribute to consecutive same char issues

        while heap:
            temp = []
            appended = False
            while heap:
                count, ch = heapq.heappop(heap)
                count = -count
                # Check if we can append this string without creating "AAA" or "BBB"
                if ch == 'A':
                    if last_char == 'A' and last_char_count == 2:
                        temp.append((-count, ch))
                        continue
                    else:
                        total_length += 2
                        if last_char == 'A':
                            last_char_count += 2
                        else:
                            last_char = 'A'
                            last_char_count = 2
                        count -= 1
                        if count > 0:
                            heapq.heappush(heap, (-count, ch))
                        # Push back other options
                        for item in temp:
                            heapq.heappush(heap, item)
                        appended = True
                        break
                elif ch == 'B':
                    if last_char == 'B' and last_char_count == 2:
                        temp.append((-count, ch))
                        continue
                    else:
                        total_length += 2
                        if last_char == 'B':
                            last_char_count += 2
                        else:
                            last_char = 'B'
                            last_char_count = 2
                        count -= 1
                        if count > 0:
                            heapq.heappush(heap, (-count, ch))
                        for item in temp:
                            heapq.heappush(heap, item)
                        appended = True
                        break
                elif ch == 'AB':
                    # "AB" is safe to append as it doesn't cause "AAA" or "BBB"
                    total_length += 2
                    # "AB" contains both characters, so last_char remains unchanged
                    # but for simplicity, we can reset last_char to '' or keep as is
                    # since "AB" doesn't contribute to consecutive same char issues
                    # We don't need to update last_char or last_char_count for "AB"
                    count -= 1
                    if count > 0:
                        heapq.heappush(heap, (-count, ch))
                    for item in temp:
                        heapq.heappush(heap, item)
                    appended = True
                    break
                else:
                    temp.append((-count, ch))
            if not appended:
                break
        return total_length

