class Solution:
    def minimizeConcatenatedLength(self, words: List[str]) -> int:
        n = len(words)
        # Precompute overlaps for all pairs in both directions
        # overlap[i][j] = maximum overlap when words[i] is joined with words[j] by appending
        # Similarly, for prepending, we can reuse the same logic with reversed roles
        overlap_append = [[0]*n for _ in range(n)]
        overlap_prepend = [[0]*n for _ in range(n)]

        def max_overlap(a: str, b: str) -> int:
            max_ov = 0
            min_len = min(len(a), len(b))
            for length in range(min_len, 0, -1):
                if a[-length:] == b[:length]:
                    return length
            return 0

        for i in range(n):
            for j in range(n):
                if i != j:
                    overlap_append[i][j] = max_overlap(words[i], words[j])
                    overlap_prepend[i][j] = max_overlap(words[j], words[i])

        # Initialize DP array
        # dp[mask][i] = minimal length of concatenation covering words in mask, ending with word i
        # For each starting word, the initial length is just the length of that word
        from math import inf
        size = 1 << n
        dp = [[inf]*n for _ in range(size)]

        for i in range(n):
            dp[1 << i][i] = len(words[i])

        # Iterate over all subsets
        for mask in range(size):
            for last in range(n):
                if dp[mask][last] == inf:
                    continue
                # Try to add a new word
                for next_word in range(n):
                    if mask & (1 << next_word):
                        continue
                    new_mask = mask | (1 << next_word)

                    # Append next_word to the current string
                    append_overlap = overlap_append[last][next_word]
                    length_append = dp[mask][last] + len(words[next_word]) - append_overlap

                    if length_append < dp[new_mask][next_word]:
                        dp[new_mask][next_word] = length_append

                    # Prepend next_word to the current string
                    prepend_overlap = overlap_prepend[last][next_word]
                    length_prepend = dp[mask][last] + len(words[next_word]) - prepend_overlap

                    if length_prepend < dp[new_mask][next_word]:
                        dp[new_mask][next_word] = length_prepend

        # The answer is the minimal length over all ending words when all words are used
        full_mask = (1 << n) - 1
        return min(dp[full_mask])

