class Solution:
    def maximumJumps(self, nums: List[int], target: int) -> int:
        n = len(nums)
        # Initialize DP array: -1 indicates unreachable
        dp = [-1] * n
        dp[0] = 0  # Starting point, no jumps needed

        for i in range(1, n):
            for j in range(i):
                diff = nums[i] - nums[j]
                # Check if the jump from j to i is valid
                if -target <= diff <= target and dp[j] != -1:
                    # Update maximum jumps to reach i
                    dp[i] = max(dp[i], dp[j] + 1)

        return dp[n - 1]

