class Solution:
    def longestAlternatingSubarray(self, nums: List[int], threshold: int) -> int:
        max_len = 0
        n = len(nums)
        i = 0
        while i < n:
            # Check if current element can start a valid subarray
            if nums[i] % 2 == 0 and nums[i] <= threshold:
                current_length = 1
                prev_parity = nums[i] % 2
                j = i + 1
                while j < n:
                    # Check if within threshold
                    if nums[j] > threshold:
                        break
                    # Check if parity alternates
                    if nums[j] % 2 != prev_parity:
                        current_length += 1
                        prev_parity = nums[j] % 2
                        j += 1
                    else:
                        break
                max_len = max(max_len, current_length)
            i += 1
        return max_len

