        max_length = -1
        current_length = 0
        expected_difference = 1

        for i in range(1, len(nums)):
            diff = nums[i] - nums[i - 1]
            if diff == expected_difference:
                if current_length == 0:
                    current_length = 2
                else:
                    current_length += 1
                expected_difference = -expected_difference
            else:
                if diff == 1:
                    current_length = 2
                    expected_difference = -1
                else:
                    current_length = 0
            if current_length > 1:
                max_length = max(max_length, current_length)

        return max_length

