class Solution:
    def findPrimePairs(self, n: int) -> List[List[int]]:
        # Edge case: if n < 4, no such pairs can exist because the smallest prime pair is (2,2) summing to 4
        if n < 4:
            return []

        # Generate prime numbers up to n using Sieve of Eratosthenes
        is_prime = [True] * (n + 1)
        is_prime[0], is_prime[1] = False, False

        for i in range(2, int(n**0.5) + 1):
            if is_prime[i]:
                for multiple in range(i * i, n + 1, i):
                    is_prime[multiple] = False

        result = []

        # Iterate through potential prime x values
        for x in range(2, n // 2 + 1):
            if is_prime[x]:
                y = n - x
                if y >= x and is_prime[y]:
                    result.append([x, y])

        return result

