class Solution:
    def minimumString(self, a: str, b: str, c: str) -> str:
        from itertools import permutations

        def merge_strings(s1: str, s2: str) -> str:
            # Find the maximum overlap between suffix of s1 and prefix of s2
            max_overlap = 0
            for i in range(1, min(len(s1), len(s2)) + 1):
                if s1[-i:] == s2[:i]:
                    max_overlap = i
            return s1 + s2[max_overlap:]

        def check_and_update(candidate: str, best: list):
            # Update the best string if candidate is shorter or lex smaller if same length
            if not best[0]:
                best[0] = candidate
            else:
                if len(candidate) < len(best[0]) or (len(candidate) == len(best[0]) and candidate < best[0]):
                    best[0] = candidate

        strings = [a, b, c]
        best_result = [None]  # Use list for mutability in nested scope

        for perm in permutations(strings):
            # Merge first two strings
            merged_ab = merge_strings(perm[0], perm[1])
            # Merge the result with the third string
            merged_abc = merge_strings(merged_ab, perm[2])
            check_and_update(merged_abc, best_result)

        return best_result[0]

class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)

        # Precompute minimal changes to convert any substring s[i:j+1] into a semi-palindrome
        # cost[i][j] = minimal changes to make s[i:j+1] semi-palindrome
        cost = [[0] * n for _ in range(n)]

        for i in range(n):
            for j in range(i, n):
                length = j - i + 1
                min_change = float('inf')
                # Check all possible d that divide the length
                for d in range(1, length):
                    if length % d == 0:
                        total_changes = 0
                        # For each group based on modulo d
                        for offset in range(d):
                            # Collect characters in this group
                            group_chars = [s[i + offset + t * d] for t in range(length // d)]
                            # To make this group a palindrome, find minimal changes
                            # by pairing characters from start and end
                            changes_for_group = 0
                            left, right = 0, len(group_chars) - 1
                            while left < right:
                                if group_chars[left] != group_chars[right]:
                                    changes_for_group += 1
                                left += 1
                                right -= 1
                            total_changes += changes_for_group
                        min_change = min(min_change, total_changes)
                cost[i][j] = min_change

        # DP array: dp[i][k] = minimal changes to partition s[:i] into k semi-palindromes
        from math import inf
        dp = [[inf] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for parts in range(1, min(i, k) + 1):
                # Try all possible previous partition points
                for j in range(parts - 1, i):
                    # s[j:i] is the last segment
                    current_cost = cost[j][i - 1]
                    if dp[j][parts - 1] + current_cost < dp[i][parts]:
                        dp[i][parts] = dp[j][parts - 1] + current_cost

        return dp[n][k]

