class Solution:
    def numberOfWays(self, n: int, x: int) -> int:
        MOD = 10**9 + 7

        # Generate all possible base numbers whose x-th power <= n
        max_base = 1
        while (max_base + 1) ** x <= n:
            max_base += 1

        # Memoization cache: key = (remaining, start), value = number of ways
        from functools import lru_cache

        @lru_cache(None)
        def count_ways(remaining, start):
            # Base case: exact sum achieved
            if remaining == 0:
                return 1
            # If remaining negative or no more numbers to consider
            if remaining < 0 or start > max_base:
                return 0

            # Include start^x
            include = count_ways(remaining - start ** x, start + 1)
            # Exclude start
            exclude = count_ways(remaining, start + 1)

            return (include + exclude) % MOD

        return count_ways(n, 1)

class Solution:
    def minimumBeautifulSubstrings(self, s: str) -> int:
        # Precompute all powers of 5 within the range of binary length (up to 15 bits)
        max_num = (1 << 15) - 1  # maximum number with 15 bits
        powers_of_5 = set()
        num = 1
        while num <= max_num:
            powers_of_5.add(num)
            num *= 5

        n = len(s)
        # Initialize DP array with infinity
        dp = [float('inf')] * (n + 1)
        dp[0] = 0  # base case: no substrings needed for empty string

        for i in range(1, n + 1):
            for j in range(i):
                substring = s[j:i]
                # Skip if leading zero (except if substring is "0" which is invalid here)
                if substring[0] == '0':
                    continue
                val = int(substring, 2)
                if val in powers_of_5:
                    dp[i] = min(dp[i], dp[j] + 1)

        return dp[n] if dp[n] != float('inf') else -1

