        # Check if length matches n + 1
        if len(nums) != n + 1:
            return False

        count_map = {}
        for num in nums:
            count_map[num] = count_map.get(num, 0) + 1

        # Check counts for numbers 1 to n-1
        for i in range(1, n):
            if count_map.get(i, 0) != 1:
                return False

        # Check count for n
        if count_map.get(n, 0) != 2:
            return False

        # Ensure no extra numbers are present
        if len(count_map) != n:
            return False

        return True

