class Solution:
    def maxSum(self, nums: List[int]) -> int:
        # Dictionary to group numbers by their maximum digit
        max_digit_groups = {}

        for num in nums:
            # Find the maximum digit in the current number
            max_digit = max(int(d) for d in str(num))
            # Append the number to the corresponding group
            if max_digit not in max_digit_groups:
                max_digit_groups[max_digit] = []
            max_digit_groups[max_digit].append(num)

        max_sum = -1
        # For each group, find the top two largest numbers
        for group in max_digit_groups.values():
            if len(group) >= 2:
                # Sort the group in descending order to get the top two
                group.sort(reverse=True)
                current_sum = group[0] + group[1]
                if current_sum > max_sum:
                    max_sum = current_sum

        return max_sum

