class Solution:
    def canSplitArray(self, nums: List[int], m: int) -> bool:
        n = len(nums)
        # Memoization cache: key = (start, end), value = True/False
        memo = {}

        # Precompute prefix sums for efficient subarray sum calculation
        prefix_sums = [0]
        for num in nums:
            prefix_sums.append(prefix_sums[-1] + num)

        def get_sum(start: int, end: int) -> int:
            return prefix_sums[end + 1] - prefix_sums[start]

        def can_split(start: int, end: int) -> bool:
            # If subarray length is 1, it's always valid
            if start == end:
                return True

            if (start, end) in memo:
                return memo[(start, end)]

            total_sum = get_sum(start, end)
            # If sum of current subarray is less than m, cannot split further
            if total_sum < m:
                memo[(start, end)] = False
                return False

            # Try all possible splits
            for mid in range(start, end):
                left_sum = get_sum(start, mid)
                right_sum = get_sum(mid + 1, end)

                # Check if splitting at mid is valid:
                # Both parts must be valid after split
                if (left_sum >= m or (mid - start + 1) == 1) and \
                   (right_sum >= m or (end - mid) == 1):
                    # Recursively check if both parts can be further split
                    if can_split(start, mid) and can_split(mid + 1, end):
                        memo[(start, end)] = True
                        return True

            # If no valid split found
            memo[(start, end)] = False
            return False

        # The entire array must be splittable
        return can_split(0, n - 1)

