class Solution:
    def countSteppingNumbers(self, low: str, high: str) -> int:
        MOD = 10**9 + 7

        def str_minus_one(num_str):
            """Subtract 1 from a large number represented as string."""
            num_list = list(num_str)
            i = len(num_list) - 1
            while i >= 0:
                if num_list[i] != '0':
                    num_list[i] = str(int(num_list[i]) - 1)
                    break
                else:
                    num_list[i] = '9'
                    i -= 1
            # Remove leading zeros if any
            res = ''.join(num_list).lstrip('0')
            return res if res else '0'

        def count_stepping_numbers(num_str):
            """Count stepping numbers less than or equal to num_str."""
            from functools import lru_cache

            digits = list(map(int, num_str))
            n = len(digits)

            @lru_cache(None)
            def dfs(pos, prev_digit, is_tight, leading_zero):
                if pos == n:
                    # Valid number formed
                    return 1

                limit = digits[pos] if is_tight else 9
                total = 0
                for d in range(limit + 1):
                    # Skip leading zeros
                    if leading_zero and d == 0:
                        # Leading zero, but we don't count zero as a valid number unless number is zero
                        total += dfs(pos + 1, -1, is_tight and d == limit, True)
                    else:
                        # For non-leading zero, check stepping condition
                        if prev_digit == -1 or abs(prev_digit - d) == 1:
                            total += dfs(pos + 1,
                                         d,
                                         is_tight and d == limit,
                                         False)
                return total % MOD

            return dfs(0, -1, True, True)

        # Count numbers ≤ high
        count_high = count_stepping_numbers(high)
        # Count numbers < low
        low_minus_one = str_minus_one(low)
        count_low = count_stepping_numbers(low_minus_one)

        result = (count_high - count_low) % MOD
        return result

