class Solution:
    def minimumTime(self, nums1: List[int], nums2: List[int], x: int) -> int:
        n = len(nums1)
        total_initial = sum(nums1)
        if total_initial <= x:
            return 0

        max_time = 10**6

        def can_achieve(T):
            values = [nums1[i] + T * nums2[i] for i in range(n)]
            values.sort(reverse=True)
            for k in range(n + 1):
                sum_after_resets = sum(values[k:])
                total_time = T + k
                if total_time <= max_time and sum_after_resets <= x:
                    return True
            return False

        left, right = 0, max_time
        result = -1
        while left <= right:
            mid = (left + right) // 2
            if can_achieve(mid):
                result = mid
                right = mid - 1
            else:
                left = mid + 1
        return result

