        diff_higher = abs(purchaseAmount - higher_multiple)
        if diff_lower < diff_higher:
            roundedAmount = lower_multiple
        elif diff_higher < diff_lower:
            roundedAmount = higher_multiple
        else:
            roundedAmount = higher_multiple
        remaining_balance = 100 - roundedAmount
        return remaining_balance

