class Solution:
    def numberOfBeautifulIntegers(self, low: int, high: int, k: int) -> int:
        from functools import lru_cache

        def count_up_to(n: int) -> int:
            if n < 0:
                return 0
            digits = list(map(int, str(n)))
            length = len(digits)

            @lru_cache(None)
            def dp(pos: int, diff: int, mod: int, tight: bool, leading_zero: bool) -> int:
                # Base case: if we've processed all digits
                if pos == length:
                    # Check if counts are balanced and divisible
                    return 1 if diff == 0 and mod == 0 and not leading_zero else 0

                limit = digits[pos] if tight else 9
                total = 0
                for dig in range(limit + 1):
                    # If tight, next digit can't exceed current limit
                    next_tight = tight and (dig == limit)
                    # Leading zeros don't count towards odd/even counts
                    next_leading_zero = leading_zero and (dig == 0)
                    # Update diff: only count if not leading zero
                    next_diff = diff
                    if not next_leading_zero:
                        if dig % 2 == 0:
                            next_diff += 1
                        else:
                            next_diff -= 1
                    # Update mod
                    next_mod = (mod * 10 + dig) % k
                    total += dp(pos + 1, next_diff, next_mod, next_tight, next_leading_zero)
                return total

            return dp(0, 0, 0, True, True)

        # Count numbers in [low, high]
        return count_up_to(high) - count_up_to(low - 1)

class Solution:
    def canMakeSubsequence(self, str1: str, str2: str) -> bool:
        n, m = len(str1), len(str2)
        # Step 1: Check if str2 is already a subsequence of str1
        i = j = 0
        while i < n and j < m:
            if str1[i] == str2[j]:
                j += 1
            i += 1
        if j == m:
            return True

        # Precompute for each position if character can be incremented to match a character in str2
        # Create a 2D boolean array: can_increment[i][c] = True if str1[i] can be incremented to match character c
        # To optimize, for each position in str1, check if it can match each character in str2 after increment
        can_match_after_increment = [set() for _ in range(n)]
        for i in range(n):
            ch = str1[i]
            for c in set(str2):
                if ch == c:
                    can_match_after_increment[i].add(c)
                elif ch == 'z' and c == 'a':
                    can_match_after_increment[i].add(c)
                elif chr(ord(ch) + 1) == c:
                    can_match_after_increment[i].add(c)

        # Build prefix match array: how much of str2 can be matched up to position i without increment
        prefix_match = [0] * (n + 1)
        j = 0
        for i in range(n):
            if j < m:
                if str1[i] == str2[j]:
                    j += 1
            prefix_match[i + 1] = j

        # Build suffix match array: how much of str2 can be matched starting from position i, considering increment
        suffix_match = [0] * (n + 1)
        j = m - 1
        for i in range(n - 1, -1, -1):
            match_found = False
            if j >= 0:
                # Check direct match
                if str1[i] == str2[j]:
                    match_found = True
                # Check incremented match
                elif str1[i] == 'z' and str2[j] == 'a':
                    match_found = True
                elif chr(ord(str1[i]) + 1) == str2[j]:
                    match_found = True
            if match_found:
                suffix_match[i] = suffix_match[i + 1] + 1
                j -= 1
            else:
                suffix_match[i] = suffix_match[i + 1]
        # Now, for each position, check if we can form str2 with at most one increment
        for i in range(n):
            prefix_len = prefix_match[i]
            suffix_len = suffix_match[i + 1] if i + 1 <= n else 0
            # Case 1: No increment needed at position i
            if prefix_len + suffix_len >= m:
                return True
            # Case 2: Increment character at position i to match str2[prefix_len]
            if prefix_len < m:
                target_char = str2[prefix_len]
                if target_char in can_match_after_increment[i]:
                    if prefix_len + 1 + suffix_len >= m:
                        return True
        return False

class Solution:
