class Solution:
    def numberOfWays(self, s: str, t: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(s)
        doubled = s + s
        pos = doubled.find(t)
        if pos == -1:
            return 0
        r = pos % n
        if s == t:
            if k == 1:
                count_same = 0
                for l in range(1, n):
                    if s == self.rotate(s, l):
                        count_same += 1
                return count_same % MOD
            elif k == 0:
                return 1
            else:
                count_same = 0
                for l in range(1, n):
                    if s == self.rotate(s, l):
                        count_same += 1
                return pow(count_same, k, MOD)
        if k == 0:
            return 1 if s == t else 0
        size = n
        def build_transition():
            matrix = [[0]*size for _ in range(size)]
            for i in range(size):
                for l in range(1, n):
                    j = (i + l) % n
                    matrix[i][j] = (matrix[i][j] + 1) % MOD
            return matrix
        def mat_mult(A, B):
            result = [[0]*size for _ in range(size)]
            for i in range(size):
                rowA = A[i]
                for j in range(size):
                    s = 0
                    for k_ in range(size):
                        s += rowA[k_] * B[k_][j]
                    result[i][j] = s % MOD
            return result
        def mat_pow(M, power):
            result = [[0]*size for _ in range(size)]
            for i in range(size):
                result[i][i] = 1
            base = M
            while power > 0:
                if power & 1:
                    result = mat_mult(result, base)
                base = mat_mult(base, base)
                power >>= 1
            return result
        transition = build_transition()
        trans_k = mat_pow(transition, k)
        answer = trans_k[0][r] % MOD
        return answer
    def rotate(self, s, l):
        return s[-l:] + s[:-l]

