class Solution:
    def minOperations(self, nums: List[int], target: int) -> int:
        # Count the frequency of each power of two in nums
        counts = [0] * 31  # since 2^30 is the max in constraints
        for num in nums:
            power = num.bit_length() - 1
            counts[power] += 1

        operations = 0
        # We'll process from the smallest bit to the largest
        for i in range(31):
            # Check if the current bit in target is set
            if (target >> i) & 1:
                # Need at least one 2^i
                if counts[i] > 0:
                    # Use one if available
                    counts[i] -= 1
                else:
                    # Need to split larger powers to get 2^i
                    j = i + 1
                    while j < 31 and counts[j] == 0:
                        j += 1
                    if j == 31:
                        # No larger power available to split
                        return -1
                    # Split larger power down to 2^i
                    while j > i:
                        # Split one 2^j into two 2^{j-1}
                        counts[j] -= 1
                        counts[j - 1] += 2
                        operations += 1
                        j -= 1
                    # Use one 2^i after splitting
                    counts[i] -= 1
            # Combine pairs of 2^i to form 2^{i+1}
            if i < 30:
                counts[i + 1] += counts[i] // 2

        return operations

