class Solution:
    def constructProductMatrix(self, grid: List[List[int]]) -> List[List[int]]:
        MOD = 12345
        if not grid:
            return []
        n = len(grid)
        m = len(grid[0]) if n > 0 else 0

        flat_grid = [cell for row in grid for cell in row]
        zero_count = 0
        total_product = 1
        for num in flat_grid:
            if num == 0:
                zero_count += 1
            else:
                total_product = (total_product * num) % MOD

        result = [[0 for _ in range(m)] for _ in range(n)]

        if zero_count > 1:
            return result
        elif zero_count == 1:
            for i in range(n):
                for j in range(m):
                    val = grid[i][j]
                    if val == 0:
                        prod = 1
                        for num in flat_grid:
                            if num != 0:
                                prod = (prod * num) % MOD
                        result[i][j] = prod
                    else:
                        result[i][j] = 0
            return result
        else:
            # No zeros: compute product excluding each element
            # Precompute prefix and suffix products for the flattened array
            prefix = [1] * (len(flat_grid) + 1)
            suffix = [1] * (len(flat_grid) + 1)
            for i in range(1, len(flat_grid) + 1):
                prefix[i] = (prefix[i - 1] * flat_grid[i - 1]) % MOD
            for i in range(len(flat_grid) - 1, -1, -1):
                suffix[i] = (suffix[i + 1] * flat_grid[i]) % MOD

            for i in range(n):
                for j in range(m):
                    idx = i * m + j
                    prod_excluding = (prefix[idx] * suffix[idx + 1]) % MOD
                    result[i][j] = prod_excluding
            return result

class Solution:
    def minOperations(self, s1: str, s2: str, x: int) -> int:
        n = len(s1)
        diff_positions = []

        # Find all positions where s1 and s2 differ
        for i in range(n):
            if s1[i] != s2[i]:
                diff_positions.append(i)

        # If the number of differences is odd, impossible to fix all
        if len(diff_positions) % 2 != 0:
            return -1

        total_cost = 0
        i = 0
        while i < len(diff_positions):
            # If there's only one difference left, can't fix it alone
            if i + 1 >= len(diff_positions):
                return -1

            # Check if the current and next difference are adjacent
            if diff_positions[i + 1] - diff_positions[i] == 1:
                # Adjacent differences: flip both at cost 1
                total_cost += 1
                i += 2
            else:
                # Non-adjacent differences: decide between flipping individually or using the first operation
                cost_pair = min(x, 2)  # flipping both individually at cost 2, or using one operation at cost x
                total_cost += cost_pair
                i += 2

        return total_cost

