        # Step 1: Sort the segments based on their start points
        nums.sort(key=lambda x: x[0])

        # Initialize a list to hold merged intervals
        merged_intervals = []

        for interval in nums:
            start, end = interval
            # If merged_intervals is empty or current interval does not overlap with the last one
            if not merged_intervals or merged_intervals[-1][1] < start:
                merged_intervals.append([start, end])
            else:
                # Overlap exists, merge by extending the end if needed
                merged_intervals[-1][1] = max(merged_intervals[-1][1], end)

        # Step 3: Calculate total covered points
        total_points = 0
        for start, end in merged_intervals:
            total_points += (end - start + 1)

        return total_points

