class Solution:
    def minimumRightShifts(self, nums: List[int]) -> int:
        n = len(nums)

        # Check if already sorted
        if all(nums[i] < nums[i+1] for i in range(n-1)):
            return 0

        # Find the index where the order breaks
        break_points = []
        for i in range(n - 1):
            if nums[i] > nums[i + 1]:
                break_points.append(i)

        # If more than one break point, impossible to sort by shifts
        if len(break_points) != 1:
            return -1

        rotation_index = break_points[0]
        shifts = n - (rotation_index + 1)

        # Rotate the array to verify if it becomes sorted
        rotated = nums[-shifts:] + nums[:-shifts]
        if all(rotated[i] < rotated[i+1] for i in range(n-1)):
            return shifts
        else:
            return -1

