            min_ops = min(min_ops, n - 1)
        for pattern in patterns:
            last_digit = pattern[1]
            first_digit = pattern[0]
            for i in range(n - 1, -1, -1):
                if num[i] == last_digit:
                    for j in range(i - 1, -1, -1):
                        if num[j] == first_digit:
                            deletions = (n - i - 1) + (i - j - 1)
