class Solution:
    def maximumSum(self, nums: List[int]) -> int:
        def get_reduced_form(num):
            reduced = []
            temp = num
            for p in range(2, int(math.sqrt(temp)) + 1):
                count = 0
                while temp % p == 0:
                    temp //= p
                    count ^= 1
                if count == 1:
                    reduced.append(p)
            if temp > 1:
                reduced.append(temp)
            reduced.sort()
            return tuple(reduced)

        groups = defaultdict(list)
        max_element = max(nums)

        for num in nums:
            form = get_reduced_form(num)
            groups[form].append(num)

        max_subset_sum = 0
        for group_nums in groups.values():
            max_subset_sum = max(max_subset_sum, max(group_nums))
        return max(max_element, max_subset_sum)

