class Solution:
    def lengthOfLongestSubsequence(self, nums: List[int], target: int) -> int:
        # Initialize DP array where index represents sum and value represents max length
        # Start with -1 indicating impossible sums, except sum 0 which is achievable with length 0
        dp = [-1] * (target + 1)
        dp[0] = 0

        for num in nums:
            # Traverse backwards to avoid using updated states in the same iteration
            for current_sum in range(target, num - 1, -1):
                if dp[current_sum - num] != -1:
                    # Update the maximum length for current_sum
                    dp[current_sum] = max(dp[current_sum], dp[current_sum - num] + 1)

        # If no subsequence sums to target, return -1
        return dp[target]

