        prefix_ones = [0] * (n + 1)
        for i in range(n):
            prefix_ones[i + 1] = prefix_ones[i] + (1 if s[i] == '1' else 0)

        for i in range(n):
            for j in range(i, n):
                # Count number of '1's in s[i:j+1]
                count_ones = prefix_ones[j + 1] - prefix_ones[i]
