class Solution:
    def minGroupsForValidAssignment(self, nums: List[int]) -> int:
        freq = Counter(nums)
        n = len(nums)
        low, high = max(freq.values()), n

        def can_assign(k: int) -> bool:
            max_size = math.ceil(n / k)
            total_groups_needed = 0
            for count in freq.values():
                total_groups_needed += math.ceil(count / max_size)
                if total_groups_needed > k:
                    return False
            return True

        while low < high:
            mid = (low + high) // 2
            if can_assign(mid):
                high = mid
            else:
                low = mid + 1

        return low

