class Solution:
    def findKOr(self, nums: List[int], k: int) -> int:
        # Handle special cases directly
        if k == 1:
            # K-or when k=1 is just the bitwise OR of all elements
            result = 0
            for num in nums:
                result |= num
            return result
        if k == len(nums):
            # K-or when k equals array length is the bitwise AND of all elements
            result = nums[0]
            for num in nums[1:]:
                result &= num
            return result

        # For general case, count how many elements have each bit set
        max_bits = 31  # since nums[i] < 2^31
        bit_counts = [0] * max_bits

        for num in nums:
            for i in range(max_bits):
                if (num >> i) & 1:
                    bit_counts[i] += 1

        result = 0
        for i in range(max_bits):
            if bit_counts[i] >= k:
                result |= (1 << i)

        return result

