            # When current index reaches the furthest last occurrence in the segment
            if i == max_last:
                count_segments += 1
                start = i + 1  # start of next segment

        # Step 3: Number of ways to partition is 2^(number of segments - 1)
        # because each boundary between segments can be cut or not
        def mod_pow(base, exp, mod):
            result = 1
            while exp > 0:
                if exp % 2 == 1:
                    result = (result * base) % mod
                base = (base * base) % mod
                exp //= 2
            return result

        # If there's only one segment, only one partition (the whole array)
        if count_segments == 1:
            return 1
        else:
            return mod_pow(2, count_segments - 1, MOD)

