class Solution:
    def lexicographicallySmallestArray(self, nums: List[int], limit: int) -> List[int]:
        # Number of elements
        n = len(nums)

        # Union-Find (Disjoint Set Union) implementation
        parent = list(range(n))

        def find(x):
            while parent[x] != x:
                parent[x] = find(parent[x])
                x = parent[x]
            return x

        def union(x, y):
            rootX = find(x)
            rootY = find(y)
            if rootX != rootY:
                parent[rootY] = rootX

        # Create a list of (value, index) and sort it
        sorted_nums = sorted([(val, idx) for idx, val in enumerate(nums)], key=lambda x: x[0])

        # Connect adjacent elements in sorted order if their difference <= limit
        for i in range(n - 1):
            val1, idx1 = sorted_nums[i]
            val2, idx2 = sorted_nums[i + 1]
            if abs(val1 - val2) <= limit:
                union(idx1, idx2)

        # Group indices by their root parent
        groups = {}
        for i in range(n):
            root = find(i)
            if root not in groups:
                groups[root] = []
            groups[root].append(i)

        # For each group, sort the values and assign back
        res = nums[:]
        for group_indices in groups.values():
            # Extract the values at these indices
            group_values = [res[i] for i in group_indices]
            # Sort the values to get lex smallest arrangement
            group_values.sort()
            # Assign sorted values back to the original indices
            for i, idx in enumerate(sorted(group_indices)):
                res[idx] = group_values[i]

        return res

