class Solution:
    def numberOfSequence(self, n: int, sick: List[int]) -> int:
        MOD = 10**9 + 7

        def mod_pow(base, exp):
            result = 1
            while exp > 0:
                if exp % 2 == 1:
                    result = (result * base) % MOD
                base = (base * base) % MOD
                exp //= 2
            return result

        result = 1

        if sick[0] > 0:
            result = (result * 1)  # Edge segment at start

        for i in range(1, len(sick)):
            gap = sick[i] - sick[i - 1] - 1
            if gap > 0:
                result = (result * mod_pow(2, gap - 1)) % MOD

        if sick[-1] < n - 1:
