class Solution:
    def maxPartitionsAfterOperations(self, s: str, k: int) -> int:
        from collections import defaultdict

        def compute_max_partitions(s: str) -> int:
            n = len(s)
            count = 0
            i = 0
            while i < n:
                freq = defaultdict(int)
                distinct = 0
                j = i
                while j < n:
                    if freq[s[j]] == 0:
                        if distinct == k:
                            break
                        distinct += 1
                    freq[s[j]] += 1
                    j += 1
                count += 1
                i = j
            return count

        n = len(s)
        baseline = compute_max_partitions(s)
        max_partitions = baseline

        for i in range(n):
            original_char = s[i]
            for c in 'abcdefghijklmnopqrstuvwxyz':
                if c == original_char:
                    continue
                s_list = list(s)
                s_list[i] = c
                new_s = ''.join(s_list)
                partitions = compute_max_partitions(new_s)
                if partitions > max_partitions:
                    max_partitions = partitions

        return max_partitions

