class Solution:
    def minimumCost(self, source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
        # Number of lowercase English letters
        n_chars = 26
        INF = float('inf')

        # Initialize the graph with infinity costs
        graph = [[INF] * n_chars for _ in range(n_chars)]

        # Cost from a character to itself is zero
        for i in range(n_chars):
            graph[i][i] = 0

        # Map characters to indices 0-25
        def char_to_index(c):
            return ord(c) - ord('a')

        # Build the graph with given direct transformation costs
        for o_char, ch_char, c in zip(original, changed, cost):
            o_idx = char_to_index(o_char)
            ch_idx = char_to_index(ch_char)
            # Keep the minimal cost if multiple edges exist
            if c < graph[o_idx][ch_idx]:
                graph[o_idx][ch_idx] = c

        # Floyd-Warshall to compute all-pairs shortest paths
        for k in range(n_chars):
            for i in range(n_chars):
                for j in range(n_chars):
                    if graph[i][k] + graph[k][j] < graph[i][j]:
                        graph[i][j] = graph[i][k] + graph[k][j]

        total_cost = 0
        for s_char, t_char in zip(source, target):
            s_idx = char_to_index(s_char)
            t_idx = char_to_index(t_char)
            # If characters are already same, no cost
            if s_char == t_char:
                continue
            # If no transformation path exists
            if graph[s_idx][t_idx] == INF:
                return -1
            total_cost += graph[s_idx][t_idx]

        return total_cost

class Solution:
    def findMaximumNumber(self, k: int, x: int) -> int:
        def total_price(n: int) -> int:
            total = 0
            for i in range(1, 51):
                cycle_length = 1 << i
                full_cycles = n // cycle_length
                count_in_full_cycles = full_cycles * (cycle_length >> 1)
                remainder = n % cycle_length
                start_bit = cycle_length >> 1
                count_in_remainder = max(0, remainder - start_bit + 1)
                count = count_in_full_cycles + count_in_remainder
                if i % x == 0:
                    total += count
            return total

        low, high = 1, 10**18
        ans = 0
        while low <= high:
            mid = (low + high) // 2
            if total_price(mid) <= k:
                ans = mid
                low = mid + 1
            else:
                high = mid - 1
        return ans

