class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        n = len(s)
        len_a = len(a)
        len_b = len(b)

        # Find all starting indices where 'a' occurs
        a_positions = []
        for i in range(n - len_a + 1):
            if s[i:i+len_a] == a:
                a_positions.append(i)

        # Find all starting indices where 'b' occurs
        b_positions = []
        for j in range(n - len_b + 1):
            if s[j:j+len_b] == b:
                b_positions.append(j)

        result = []
        # For each position where 'a' occurs, check if there's a 'b' within distance k
        for i in a_positions:
            # We want to find if there's any j in b_positions such that |j - i| <= k
            # Since b_positions is sorted, we can use binary search for efficiency
            left, right = 0, len(b_positions) - 1
            while left <= right:
                mid = (left + right) // 2
                j = b_positions[mid]
                if abs(j - i) <= k:
                    result.append(i)
                    break
                elif j < i - k:
                    left = mid + 1
                else:
                    right = mid - 1
        return result

