        prefix_sum = [0] * (n + 1)
        for i in range(n):
            prefix_sum[i + 1] = prefix_sum[i] + nums[i]
        max_sum = float('-inf')
        start_value_map = dict()
        for j in range(n):
            current_value = nums[j]
            for target in [current_value - k, current_value + k]:
                if target in start_value_map:
                    start_idx = start_value_map[target][1]
                    sub_sum = prefix_sum[j + 1] - prefix_sum[start_idx]
                    if sub_sum > max_sum:
