        def count_set_bits(n: int) -> int:
            count = 0
            while n:
                n &= n - 1
                count += 1
            return count

        sorted_nums = sorted(nums)
        for i in range(len(nums)):
            if count_set_bits(nums[i]) != count_set_bits(sorted_nums[i]):
                return False

        original_groups = defaultdict(list)
        sorted_groups = defaultdict(list)

        for num in nums:
            original_groups[count_set_bits(num)].append(num)
        for num in sorted_nums:
            sorted_groups[count_set_bits(num)].append(num)

        for bits in original_groups:
            if Counter(original_groups[bits]) != Counter(sorted_groups[bits]):
                return False

        return True

