        n = len(nums)
        m = len(changeIndices)
        count_occurrences = [0] * (n + 1)
        for idx in changeIndices:
            count_occurrences[idx] += 1
        required_decrements = [0] * (n + 1)
        for i in range(n):
            if nums[i] > 0:
                required_decrements[i + 1] = nums[i]
        def can_mark_all(s):
            total_appearances = [0] * (n + 1)
            for i in range(s):
                total_appearances[changeIndices[i]] += 1
            for i in range(1, n + 1):
                if nums[i - 1] == 0:
                    continue
                if total_appearances[i] < required_decrements[i]:
                    return False
            return True
        left, right = 1, m
        answer = -1
        while left <= right:
            mid = (left + right) // 2
            if can_mark_all(mid):
                answer = mid
                right = mid - 1
            else:
                left = mid + 1
        return answer

