                candies.append((i, j))

    # All key points: start, candies, goal
    key_points = [start] + candies + [goal]
    n_points = len(key_points)
    start_idx = 0
    goal_idx = n_points - 1

    # Directions for BFS
    directions = [(-1,0),(1,0),(0,-1),(0,1)]

    # Function to run BFS from a point
    def bfs(sx, sy):
        dist = [[-1]*W for _ in range(H)]
        dist[sx][sy] = 0
        queue = deque()
        queue.append((sx, sy))
        while queue:
            x, y = queue.popleft()
            for dx, dy in directions:
                nx, ny = x+dx, y+dy
                if 0 <= nx < H and 0 <= ny < W:
                    if grid[nx][ny] != '#' and dist[nx][ny] == -1:
                        dist[nx][ny] = dist[x][y] + 1
                        queue.append((nx, ny))
        return dist

    # Precompute shortest distances between key points
    dist_matrix = [[-1]*n_points for _ in range(n_points)]
    all_dists = []
    for i, (x, y) in enumerate(key_points):
        dist = bfs(x, y)
        all_dists.append(dist)
    for i in range(n_points):
        for j in range(n_points):
            if i == j:
                dist_matrix[i][j] = 0
            else:
                x2, y2 = key_points[j]
                dist = all_dists[i][x2][y2]
                dist_matrix[i][j] = dist

    # Check reachability
    for i in range(n_points):
        for j in range(n_points):
            if dist_matrix[i][j] == -1:
                # If any required path is unreachable, no need to proceed
                pass

    # Number of candies
    candy_count = len(candies)

    # DP array: dp[current_node][bitmask_of_candies] = minimal moves
    # Initialize with a large number
    INF = 10**9
    dp = [[INF]*(1<<candy_count) for _ in range(n_points)]
    # Start at start node with no candies collected
    dp[start_idx][0] = 0

    for mask in range(1<<candy_count):
        for u in range(n_points):
            if dp[u][mask] == INF:
                continue
            current_moves = dp[u][mask]
            # Try to go to other candies
            for c_idx in range(candy_count):
                if not (mask & (1 << c_idx)):
                    v = c_idx + 1  # candies are at indices 1..candy_count
                    cost = dist_matrix[u][v]
                    if cost != -1:
                        new_moves = current_moves + cost
                        if new_moves <= T and new_moves < dp[v][mask | (1 << c_idx)]:
                            dp[v][mask | (1 << c_idx)] = new_moves
            # Try to go to goal
            v = goal_idx
            cost = dist_matrix[u][v]
            if cost != -1:
                new_moves = current_moves + cost
                if new_moves <= T and new_moves < dp[v][mask]:
                    dp[v][mask] = new_moves

    # Find maximum candies collected when at goal
    max_candies = -1
    for mask in range(1<<candy_count):
        if dp[goal_idx][mask] <= T:
            candies_collected = bin(mask).count('1')
            if candies_collected > max_candies:
                max_candies = candies_collected

    print(max_candies)

