    pow52[i] = (pow52[i - 1] * 52) % MOD

# States:
# 0: no pattern matched
# 1: first uppercase matched (waiting for second uppercase)
# 2: first two uppercase matched and equal
# 3: pattern partially matched, waiting for lowercase at position 3
# 4: pattern fully matched (invalid, sequences to exclude)
# We count sequences avoiding state 4

dp = [0, 0, 0, 0]
dp[0] = 1

def get_char_options(c):
    if c == '?':
        return list(range(52))
    elif 'A' <= c <= 'Z':
        return [ord(c) - ord('A')]
    elif 'a' <= c <= 'z':
        return [ord(c) - ord('a') + 26]
    else:
        return []

def is_upper(idx):
    return 0 <= idx <= 25

def is_lower(idx):
    return 26 <= idx <= 51

for c in S:
    options = get_char_options(c)
    new_dp = [0, 0, 0, 0]
    for state in range(4):
        count = dp[state]
        if count == 0:
            continue
        for ch in options:
            upper_char = is_upper(ch)
            lower_char = is_lower(ch)
            if state == 0:
                if upper_char:
                    new_dp[1] = (new_dp[1] + count) % MOD
                else:
                    new_dp[0] = (new_dp[0] + count) % MOD
            elif state == 1:
                if upper_char:
                    # Transition to state 2 if same uppercase character
                    # Since we don't track specific uppercase, assume all uppercase can match
                    # and move to state 2
                    new_dp[2] = (new_dp[2] + count) % MOD
                else:
                    new_dp[1] = (new_dp[1] + count) % MOD
            elif state == 2:
                if upper_char:
                    # Stay in state 2
                    new_dp[2] = (new_dp[2] + count) % MOD
                elif lower_char:
                    # Move to pattern partial match
                    new_dp[3] = (new_dp[3] + count) % MOD
                else:
                    new_dp[2] = (new_dp[2] + count) % MOD
            elif state == 3:
                if lower_char:
                    # Pattern fully matched, discard sequences
                    pass
                elif upper_char:
                    # Stay in state 3 or move to state 2? For avoiding pattern, stay in 3
                    new_dp[3] = (new_dp[3] + count) % MOD
                else:
                    new_dp[3] = (new_dp[3] + count) % MOD
    dp = new_dp

total = pow52[q]
answer = sum(dp) % MOD
print(answer)

