def differ_by_one(s1, s2):
    # Count how many characters differ between s1 and s2
    diff_count = 0
    for c1, c2 in zip(s1, s2):
        if c1 != c2:
            diff_count += 1
        if diff_count > 1:
            return False
    return diff_count == 1

def can_rearrange(strings):
    for perm in permutations(strings):
        valid = True
        for i in range(len(perm) - 1):
            if not differ_by_one(perm[i], perm[i+1]):
                valid = False
                break
        if valid:
            return True
    return False

