import math

def main():
    input = sys.stdin.read().strip().split()
    N, T, M = map(int, input[0:3])
    pairs = list(zip(map(int, input[3::2]), map(int, input[4::2])))

    total = 0
    for mask in range(1 << M):
        parent = list(range(N+1))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            pa, pb = find(a), find(b)
            if pa != pb:
                parent[pb] = pa

        bits_set = 0
        for i in range(M):
            if (mask >> i) & 1:
                a, b = pairs[i]
                union(a, b)
                bits_set += 1

        components = set()
        for i in range(1, N+1):
            components.add(find(i))
        num_blocks = len(components)

        ways = T ** num_blocks
        if bits_set % 2 == 0:
            total += ways
        else:
            total -= ways

    surjective_sum = 0
    for k in range(T+1):
        surjective_sum += ((-1)**k) * math.comb(T, k) * (T - k) ** N

    answer = total * surjective_sum
    print(answer)

