def solve():
    import sys
    input = sys.stdin.read
    data = input().splitlines()

    N, M = map(int, data[0].split())
    grid = data[1:]

    def is_black(r, c):
        return grid[r][c] == '#'

    def in_bounds(r, c):
        return 0 <= r < N and 0 <= c < M

    def check_block(r_start, c_start):
        for dr in range(3):
            for dc in range(3):
                r = r_start + dr
                c = c_start + dc
                if not in_bounds(r, c) or not is_black(r, c):
                    return False
        return True

    def check_surrounding(r_start, c_start):
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                r = r_start + dr
                c = c_start + dc
                # Skip cells inside the 3x3 block
                if 0 <= dr < 3 and 0 <= dc < 3:
                    continue
                if in_bounds(r, c):
                    if is_black(r, c):
                        return False
        return True

    results = []

    for i in range(N - 8):
        for j in range(M - 8):
            # Check top-left 3x3 block
            if not check_block(i, j):
                continue
            # Check bottom-right 3x3 block
            if not check_block(i + 6, j + 6):
                continue
            # Check surrounding cells of top-left block
            if not check_surrounding(i, j):
                continue
            # Check surrounding cells of bottom-right block
            if not check_surrounding(i + 6, j + 6):
                continue
            results.append((i + 1, j + 1))

    results.sort()
    for r, c in results:
        print(r, c)

