    # Initialize counts and active flags
    row_counts = [W] * H
    col_counts = [H] * W
    active_rows = [True] * H
    active_cols = [True] * W

    # To track if a row or column is affected in the current iteration
    row_uniform = [False] * H
    col_uniform = [False] * W

    # Marked array to mark cookies for removal
    marked = [[False] * W for _ in range(H)]

    # Function to check and mark uniform rows
    def mark_rows():
        changed = False
        for i in range(H):
            if not active_rows[i] or row_counts[i] < 2:
                continue
            # Check if all remaining cookies in row i are the same
            first_color = None
            count = 0
            for j in range(W):
                if grid[i][j] != '.' and grid[i][j] is not None:
                    if first_color is None:
                        first_color = grid[i][j]
                        count = 1
                    elif grid[i][j] == first_color:
                        count += 1
                    else:
                        first_color = None
                        break
            if first_color is not None and count >= 2:
                # Mark all cookies of this color in row i
                for j in range(W):
                    if grid[i][j] == first_color:
                        if not marked[i][j]:
                            marked[i][j] = True
                            changed = True
        return changed

    # Function to check and mark uniform columns
    def mark_cols():
        changed = False
        for j in range(W):
            if not active_cols[j] or col_counts[j] < 2:
                continue
            first_color = None
            count = 0
            for i in range(H):
                if grid[i][j] != '.' and grid[i][j] is not None:
                    if first_color is None:
                        first_color = grid[i][j]
                        count = 1
                    elif grid[i][j] == first_color:
                        count += 1
                    else:
                        first_color = None
                        break
            if first_color is not None and count >= 2:
                # Mark all cookies of this color in column j
                for i in range(H):
                    if grid[i][j] == first_color:
                        if not marked[i][j]:
                            marked[i][j] = True
                            changed = True
        return changed

    while True:
        # Mark cookies based on row and column uniformity
        changed_rows = mark_rows()
        changed_cols = mark_cols()
        if not (changed_rows or changed_cols):
            break  # No more cookies to mark, terminate

        # Remove marked cookies
        for i in range(H):
            for j in range(W):
                if marked[i][j]:
                    # Remove cookie
                    grid[i][j] = '.'
                    row_counts[i] -= 1
                    col_counts[j] -= 1
                    marked[i][j] = False  # reset for next iteration

        # Update active rows and columns
        for i in range(H):
            if active_rows[i] and row_counts[i] < 2:
                active_rows[i] = False
        for j in range(W):
            if active_cols[j] and col_counts[j] < 2:
                active_cols[j] = False

