import sys
import itertools

def read_input():
    grid_lines = [sys.stdin.readline().strip() for _ in range(12)]
    polyominoes = []
    for i in range(3):
        shape_lines = grid_lines[i*4:(i+1)*4]
        shape_cells = []
        for r in range(4):
            for c in range(4):
                if shape_lines[r][c] == '#':
                    shape_cells.append((r, c))
        polyominoes.append(shape_cells)
    return polyominoes

def normalize(shape):
    min_r = min(r for r, c in shape)
    min_c = min(c for r, c in shape)
    normalized = sorted((r - min_r, c - min_c) for r, c in shape)
    return normalized

def rotate(shape):
    return [(c, -r) for r, c in shape]

def generate_orientations(shape):
    orientations = []
    current = shape
    for _ in range(4):
        current = rotate(current)
        norm = normalize(current)
        if norm not in orientations:
            orientations.append(norm)
    return orientations

def get_all_shapes(polyominoes):
    all_shapes = []
    for shape in polyominoes:
        orientations = generate_orientations(shape)
        all_shapes.append(orientations)
    return all_shapes

def can_place(grid, shape, top, left):
    for r, c in shape:
        nr, nc = top + r, left + c
        if nr < 0 or nr >= 4 or nc < 0 or nc >= 4:
            return False
        if grid[nr][nc]:
            return False
    return True

def place_shape(grid, shape, top, left, val):
    for r, c in shape:
        grid[top + r][left + c] = val

def backtrack(grid, shapes_list, used, index):
    if index == len(shapes_list):
        return True
    for shape_idx, shape_orients in enumerate(shapes_list):
        if used[shape_idx]:
            continue
        for orientation in shape_orients:
            for r in range(4):
                for c in range(4):
                    if can_place(grid, orientation, r, c):
                        place_shape(grid, orientation, r, c, True)
                        used[shape_idx] = True
                        if backtrack(grid, shapes_list, used, index + 1):
                            return True
                        place_shape(grid, orientation, r, c, False)
                        used[shape_idx] = False
    return False

