def is_one_edit_away(s, t):
    # Check if s can be converted to t with at most one edit
    len_s = len(s)
    len_t = len(t)
    if abs(len_s - len_t) > 1:
        return False

    # When lengths are equal: check for at most one substitution
    if len_s == len_t:
        diff_count = 0
        for a, b in zip(s, t):
            if a != b:
                diff_count += 1
                if diff_count > 1:
                    return False
        return True

    # When s is longer by one: check if s can become t by deleting one char
    if len_s == len_t + 1:
        i = j = 0
        diff_found = False
        while i < len_s and j < len_t:
            if s[i] != t[j]:
                if diff_found:
                    return False
                diff_found = True
                i += 1
            else:
                i += 1
                j += 1
        # If no mismatch found till end, the last char in s is the extra
        return True

    # When t is longer by one: check if s can become t by inserting one char
    if len_t == len_s + 1:
        i = j = 0
        diff_found = False
        while i < len_s and j < len_t:
            if s[i] != t[j]:
                if diff_found:
                    return False
                diff_found = True
                j += 1
            else:
                i += 1
                j += 1
        # If no mismatch found till end, the last char in t is the extra
        return True

    return False

