import sys

def main():
    input = sys.stdin.read().strip().split()
    N = int(input[0])
    D = list(map(int, input[1:1+N]))
    L1, C1, K1 = map(int, input[1+N:4+N])
    L2, C2, K2 = map(int, input[4+N:7+N])

    # Generate all feasible (x, y) combinations for each section
    section_combos = []
    for d in D:
        combos = []
        max_x = math.ceil(d / L1)
        max_y = math.ceil(d / L2)
        for x in range(max_x + 1):
            for y in range(max_y + 1):
                if x * L1 + y * L2 >= d:
                    combos.append((x, y))
        section_combos.append(combos)

    INF = 10**15
    # Initialize DP: dp[i][used1][used2] = minimal cost to cover first i sections
    # Dimensions: (N+1) x (K1+1) x (K2+1)
    dp = [[[INF]*(K2+1) for _ in range(K1+1)] for _ in range(N+1)]
    dp[0][0][0] = 0

    for i in range(N):
        for used1 in range(K1+1):
            for used2 in range(K2+1):
                if dp[i][used1][used2] == INF:
                    continue
                for (x, y) in section_combos[i]:
                    new_used1 = used1 + x
                    new_used2 = used2 + y
                    if new_used1 <= K1 and new_used2 <= K2:
                        cost = dp[i][used1][used2] + x * C1 + y * C2
                        if cost < dp[i+1][new_used1][new_used2]:
                            dp[i+1][new_used1][new_used2] = cost

    ans = -1
    for used1 in range(K1+1):
        for used2 in range(K2+1):
            if dp[N][used1][used2] != INF:
                if ans == -1 or dp[N][used1][used2] < ans:
                    ans = dp[N][used1][used2]

    print(ans)

