import sys
import itertools

def find(parent, x):
    while parent[x] != x:
        parent[x] = parent[parent[x]]
        x = parent[x]
    return x

def union(parent, rank, x, y):
    rx = find(parent, x)
    ry = find(parent, y)
    if rx != ry:
        if rank[rx] < rank[ry]:
            parent[rx] = ry
        elif rank[rx] > rank[ry]:
            parent[ry] = rx
        else:
            parent[ry] = rx
            rank[rx] += 1
        return True
    return False

def is_spanning_tree(edges, n):
    parent = [i for i in range(n+1)]
    rank = [0]*(n+1)
    count = 0
    for u, v, w in edges:
        if union(parent, rank, u, v):
            count += 1
    # Check if all vertices are connected
    root = find(parent, 1)
    for i in range(2, n+1):
        if find(parent, i) != root:
            return False
    return count == n-1

def main():
    input = sys.stdin.read().strip().split()
    N, M, K = int(input[0]), int(input[1]), int(input[2])
    edges = []
    idx = 3
    for _ in range(M):
        u, v, w = int(input[idx]), int(input[idx+1]), int(input[idx+2])
        edges.append((u, v, w))
        idx += 3

    min_modulo = None

    # Generate all subsets of edges of size N-1
    for subset in itertools.combinations(edges, N-1):
        # Check if subset forms a spanning tree
        if is_spanning_tree(subset, N):
            total_weight = sum(w for _, _, w in subset)
            total_mod = total_weight % K
            if (min_modulo is None) or (total_mod < min_modulo):
                min_modulo = total_mod

    print(min_modulo)

