import sys
sys.setrecursionlimit(10**7)

def modinv(a, m=MOD):
    # Fermat's little theorem for modular inverse
    return pow(a, m-2, m)

def main():
    input = sys.stdin.read
    data = input().split()
    H, W = map(int, data[0:2])
    grid = data[2:]

    # Directions for adjacency
    directions = [(-1,0),(1,0),(0,-1),(0,1)]

    # Step 1: Find initial green components using DFS
    visited = [[False]*W for _ in range(H)]
    comp_id = [[-1]*W for _ in range(H)]
    comp_count = 0

    def dfs(r, c):
        stack = [(r,c)]
        visited[r][c] = True
        comp_id[r][c] = comp_count
        while stack:
            x, y = stack.pop()
            for dx, dy in directions:
                nx, ny = x+dx, y+dy
                if 0 <= nx < H and 0 <= ny < W:
                    if not visited[nx][ny] and grid[nx][ny] == '#':
                        visited[nx][ny] = True
                        comp_id[nx][ny] = comp_count
                        stack.append((nx, ny))

    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#' and not visited[i][j]:
                dfs(i,j)
                comp_count += 1

    initial_components = comp_count

    # Count total red cells
    red_cells = []
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                red_cells.append((i,j))
    R = len(red_cells)

    # For each red cell, determine how the component count changes
    total_new_components = 0

    for (x, y) in red_cells:
        adjacent_components = set()
        for dx, dy in directions:
            nx, ny = x+dx, y+dy
            if 0 <= nx < H and 0 <= ny < W:
                if grid[nx][ny] == '#':
                    adjacent_components.add(comp_id[nx][ny])
        k = len(adjacent_components)
        if k == 0:
            # No adjacent green component, new component formed
            new_components = initial_components + 1
        elif k == 1:
            # Connects to one component, no change
            new_components = initial_components
        else:
            # Merges k components into one, reduces total by (k-1)
            new_components = initial_components - (k - 1)
        total_new_components += new_components

    if R == 0:
        # No red cells, expectation is zero
        print(0)
        return

    inv_R = modinv(R)
    answer = (total_new_components * inv_R) % MOD
    print(answer)

if __name__ == "__main__":
    main()

