def main():
    input_str = sys.stdin.read()
    data = input_str.split()
    H, W, K = map(int, data[:3])
    grid = data[3:]
    if K > H and K > W:
        print(-1)
        return

    # Check if already satisfied
    for i in range(H):
        for start in range(W - K + 1):
            if all(c == 'o' for c in grid[i][start:start+K]):
                print(0)
                return
    if K <= H:
        for j in range(W):
            for start in range(H - K + 1):
                if all(grid[i][j] == 'o' for i in range(start, start + K)):
                    print(0)
                    return

    min_operations = float('inf')
    found_sequence = False

    # Check horizontal sequences
    for i in range(H):
        row = grid[i]
        count_dot = 0
        blocked = False
        # Initialize first window
        for j in range(K):
            if row[j] == 'x':
                blocked = True
            elif row[j] == '.':
                count_dot += 1
        if not blocked:
            min_operations = min(min_operations, count_dot)
            found_sequence = True
        # Slide over the row
        for start in range(1, W - K + 1):
            prev_char = row[start - 1]
            new_char = row[start + K - 1]
            if prev_char == 'x':
                # previous window was blocked, no need to update
                pass
            else:
                if prev_char == '.':
                    count_dot -= 1
            if new_char == 'x':
                blocked = True
            elif new_char == '.':
                count_dot += 1
            # If previous window was blocked, check if current window is blocked
            # But since blocked is only set when 'x' is encountered, we need to reset blocked
            # at each window start
            # So, re-evaluate blocked for current window
            # To optimize, we can check if any 'x' in current window
            # But to keep it simple, check if current window contains 'x'
            window = row[start:start+K]
            if 'x' in window:
                blocked = True
            else:
                blocked = False
            if not blocked:
                min_operations = min(min_operations, count_dot)
                found_sequence = True

    # Check vertical sequences
    if K <= H:
        for j in range(W):
            col = [grid[i][j] for i in range(H)]
            count_dot = 0
            blocked = False
            for i in range(K):
                if col[i] == 'x':
                    blocked = True
                elif col[i] == '.':
                    count_dot += 1
            if not blocked:
                min_operations = min(min_operations, count_dot)
                found_sequence = True
            for start in range(1, H - K + 1):
                prev_char = col[start - 1]
                new_char = col[start + K - 1]
                if prev_char == 'x':
                    pass
                else:
                    if prev_char == '.':
                        count_dot -= 1
                if new_char == 'x':
                    blocked = True
                elif new_char == '.':
                    count_dot += 1
                window = col[start:start+K]
                if 'x' in window:
                    blocked = True
                else:
                    blocked = False
                if not blocked:
                    min_operations = min(min_operations, count_dot)
                    found_sequence = True

    if not found_sequence:
        print(-1)
    else:
        print(min_operations)
