def main():
    data = input().split()
    N = int(data[0])
    M = int(data[1])
    X = list(map(int, data[2:]))

    def dist(a, b):
        diff = abs(a - b)
        return min(diff, N - diff)

    total_length = 0
    for i in range(M - 1):
        total_length += dist(X[i], X[i + 1])

    bridge_contrib = [0] * N

    for i in range(M - 1):
        a = X[i]
        b = X[i + 1]
        d = dist(a, b)

        clockwise_dist = (b - a) % N
        counter_dist = (a - b) % N

        if clockwise_dist <= counter_dist:
            start, end = a, b
            if start > end:
                start, end = end, start
            for j in range(start, end):
                bridge_idx = (j - 1) % N
                bridge_contrib[bridge_idx] += d
        else:
            start, end = a, b
            if start > end:
                start, end = end, start
            j = start
            while j != end:
                bridge_idx = (j - 1) % N
                bridge_contrib[bridge_idx] += d
                j = (j % N) + 1

    min_tour = float('inf')
    for i in range(N):
        candidate = total_length - bridge_contrib[i]
        if candidate < min_tour:
            min_tour = candidate

    print(min_tour)

