import sys
from collections import deque

def main():
    data = sys.stdin.read().split()
    N, M = int(data[0]), int(data[1])
    edges = data[2:2+2*M]
    W = list(map(int, data[2+2*M:2+2*M+N]))
    A = list(map(int, data[2+2*M+N:2+2*M+2*N]))

    adj = [[] for _ in range(N)]
    for i in range(M):
        u = int(edges[2*i]) - 1
        v = int(edges[2*i+1]) - 1
        adj[u].append(v)
        adj[v].append(u)

    neighbor_weight_sum = [0]*N
    for i in range(N):
        s = 0
        for nb in adj[i]:
            s += W[nb]
        neighbor_weight_sum[i] = s

    total_pieces = sum(A)

    def can(K):
        size = N + 2
        source = N
        sink = N + 1
        capacity = [[0]*size for _ in range(size)]

        for i in range(N):
            capacity[source][i] = A[i]

        for i in range(N):
            # The maximum number of times vertex i can send out pieces is limited by:
            # initial A[i], and the neighbor sum constraints
            # The total number of pieces vertex i can send is at most A[i], but also constrained by neighbor sum
            # For feasibility, set capacity from vertex to sink as min(A[i], neighbor_weight_sum[i] // W[i]) if W[i] != 0
            # Since W[i] > 0 per problem statement, safe to do
            max_send = min(A[i], neighbor_weight_sum[i] // W[i]) if W[i] != 0 else 0
            capacity[i][sink] = max_send

        for u in range(N):
            for v in adj[u]:
                capacity[u][v] = K
                capacity[v][u] = K

        flow = 0
        while True:
            level = [-1]*size
            level[source] = 0
            queue = deque([source])
            while queue:
                u = queue.popleft()
                for v in range(size):
                    if capacity[u][v] > 0 and level[v] < 0:
                        level[v] = level[u]+1
                        queue.append(v)
            if level[sink] < 0:
                break
            iter = [0]*size
            def dfs(u, f):
                if u == sink:
                    return f
                while iter[u] < size:
                    v = iter[u]
                    if capacity[u][v] > 0 and level[v] == level[u]+1:
                        pushed = dfs(v, min(f, capacity[u][v]))
                        if pushed > 0:
                            capacity[u][v] -= pushed
                            capacity[v][u] += pushed
                            return pushed
                    iter[u] += 1
                return 0
            while True:
                pushed = dfs(source, 10**9)
                if pushed == 0:
                    break
                flow += pushed
        return flow >= K

    low, high = 0, total_pieces
    while low < high:
        mid = (low + high + 1)//2
        if can(mid):
            low = mid
        else:
            high = mid - 1

    print(low)

