def is_palindrome(num):
    s = str(num)
    return s == s[::-1]

def main():
    N = int(sys.stdin.read().strip())
    # Compute the maximum possible x such that x^3 <= N
    x_max = int(round(N ** (1/3))) + 2  # a small buffer to ensure we don't miss the boundary
    # Adjust x_max downward if necessary
    while (x_max ** 3) > N:
        x_max -= 1
    while ((x_max + 1) ** 3) <= N:
        x_max += 1

    max_palindrome_cube = 0
    for x in range(1, x_max + 1):
        cube = x ** 3
        if cube > N:
            break
        if is_palindrome(cube):
            if cube > max_palindrome_cube:
                max_palindrome_cube = cube

    print(max_palindrome_cube)

